const body = $input.first().json.body;
if (!body || !body.owner || !body.repo || !body.token) throw new Error('owner, repo, token required');
return [{ json: body }];

const verify = $('Extract body').first().json;
const gql = $input.first().json;
const repo = gql.data?.repository;
if (!repo) throw new Error('GraphQL returned no repository: ' + JSON.stringify(gql).slice(0,300));
const entries = repo.sections?.entries || [];
const tsxFiles = entries.filter(e => e.name.endsWith('.tsx'));
let sectionsText = '';
for (const f of tsxFiles) sectionsText += `

=== src/sections/${f.name} ===
` + (f.object?.text || '');
const claudeMd = repo.claudeMd?.text || '';
const prompt = `You are analyzing a developer portfolio (Vite + React SPA) to build a manifest of portfolio items.

Given the following section files (.tsx) and the CLAUDE.md context, produce a JSON manifest of distinct portfolio items.

[CLAUDE.md]
${claudeMd}

[Section files]${sectionsText}

Output JSON only matching this schema:
{
  "version": "1.0",
  "items": [
    { "id": "kebab-id", "type": "project|skill|award|experience", "section": "Projects|About|...", "title": "...", "description": "...", "tags": ["..."], "source_file": "src/sections/X.tsx" }
  ]
}

Ids must be unique, kebab-case, prefixed by type (project-, skill-, award-, experience-).
Respond in Korean for title/description if the source content is Korean.`;
return [{ json: { owner: verify.owner, repo: verify.repo, token: verify.token, prompt } }];

const prev = $('Build prompt').first().json;
const res = $input.first().json;
const text = res.candidates?.[0]?.content?.parts?.[0]?.text;
if (!text) throw new Error('Gemini no text: ' + JSON.stringify(res).slice(0,300));
let parsed;
try { parsed = JSON.parse(text); } catch (e) { throw new Error('Non-JSON response: ' + text.slice(0,300)); }
if (!parsed.items || !Array.isArray(parsed.items)) throw new Error('Manifest missing items[]');
parsed.generated_at = new Date().toISOString();
parsed.version = parsed.version || '1.0';
const content = Buffer.from(JSON.stringify(parsed, null, 2) + '\n').toString('base64');
return [{ json: { owner: prev.owner, repo: prev.repo, token: prev.token, content, itemCount: parsed.items.length } }];
